    return 'flag{' in text.lower() or 'ctf{' in text.lower()

def analyze_bytes(result):
    # Count printable characters
    printable_count = sum(1 for b in result if is_printable(b))
    printable_ratio = printable_count / len(result)

    try:
        ascii_str = result.decode('ascii', errors='replace')
        return ascii_str, printable_ratio
    except:
        return None, printable_ratio

def main():
    # The target byte sequence
